export type Role = 'student' | 'teacher' | 'parent';

export type RiskLevel = 'low' | 'medium' | 'high';

export interface Subject {
  id: string;
  name: string;
  progress: number;
  score: number;
  risk: RiskLevel;
}

export interface Student {
  id: string;
  name: string;
  grade: string;
  riskLevel: RiskLevel;
  issueSummary: string;
  attendance: number;
  missingTasks: string[];
  recentScores: number[];
  subjects: Subject[];
}

export interface TeacherNote {
  id: string;
  date: string;
  text: string;
  category: 'academic' | 'behavioral' | 'emotional';
}

export interface HelpRequest {
  id: string;
  studentId: string;
  subject: string;
  message: string;
  timestamp: string;
  isAnonymous: boolean;
  status: 'pending' | 'resolved';
}

