import React from 'react';
import { RiskLevel } from '../types';
import { RISK_COLORS } from '../constants';

interface CardProps {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
}

export const Card: React.FC<CardProps> = ({ children, className = '', onClick }) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-3xl p-5 shadow-sm border border-slate-100 ${onClick ? 'active:scale-95 transition-transform' : ''} ${className}`}
  >
    {children}
  </div>
);

export const Badge: React.FC<{ level: RiskLevel; label?: string }> = ({ level, label }) => {
  const colors = RISK_COLORS[level];
  return (
    <span className={`px-3 py-1 rounded-full text-xs font-semibold border ${colors.bg} ${colors.text} ${colors.border}`}>
      {label || level.charAt(0).toUpperCase() + level.slice(1)}
    </span>
  );
};

export const ProgressBar: React.FC<{ progress: number; color?: string }> = ({ progress, color = 'bg-blue-500' }) => (
  <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
    <div 
      className={`h-full rounded-full transition-all duration-500 ${color}`} 
      style={{ width: `${progress}%` }}
    />
  </div>
);

export const Header: React.FC<{ title: string; subtitle?: string; avatar?: string; onBack?: () => void }> = ({ title, subtitle, avatar, onBack }) => (
  <div className="flex items-center justify-between mb-6 pt-4">
    <div className="flex items-center gap-3">
      {onBack && (
        <button onClick={onBack} className="p-2 -ml-2 rounded-full active:bg-slate-100">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
        </button>
      )}
      <div>
        <h1 className="text-2xl font-bold text-slate-800">{title}</h1>
        {subtitle && <p className="text-slate-500 text-sm">{subtitle}</p>}
      </div>
    </div>
    {avatar && (
      <img src={avatar} alt="Avatar" className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
    )}
  </div>
);

export const BottomNav: React.FC<{ activeTab: string; onChange: (tab: string) => void; items: { id: string; label: string; icon: React.ReactNode }[] }> = ({ activeTab, onChange, items }) => (
  <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between safe-bottom z-50">
    {items.map((item) => (
      <button
        key={item.id}
        onClick={() => onChange(item.id)}
        className={`flex flex-col items-center gap-1 transition-colors ${activeTab === item.id ? 'text-blue-600' : 'text-slate-400'}`}
      >
        {item.icon}
        <span className="text-[10px] font-medium">{item.label}</span>
      </button>
    ))}
  </div>
);

import React from 'react';
import { Card, Header, Badge, ProgressBar } from '../components/Shared';
import { Student } from '../types';
import { PARENT_TIPS } from '../constants';

interface Props {
  student: Student;
  onNavigate: (screen: string) => void;
}

export const ParentDashboard: React.FC<Props> = ({ student, onNavigate }) => {
  return (
    <div className="pb-24">
      <Header 
        title={`Hello, Mr./Ms. ${student.name.split(' ')[1]}`} 
        subtitle={`Parent Portal: ${student.name}`}
        avatar="https://api.dicebear.com/7.x/initials/svg?seed=Parent"
      />

      <div className="space-y-6">
        <section>
          <h2 className="text-lg font-bold text-slate-800 mb-3">Academic Summary</h2>
          <div className="grid grid-cols-2 gap-4">
            {student.subjects.slice(0, 2).map(sub => (
              <Card key={sub.id} className="p-4">
                <div className="flex justify-between items-center mb-1">
                  <span className="text-xs font-bold text-slate-500 uppercase">{sub.id}</span>
                  <Badge level={sub.risk} />
                </div>
                <div className="text-2xl font-bold text-slate-800 mb-2">{sub.score}%</div>
                <ProgressBar progress={sub.progress} color={sub.risk === 'high' ? 'bg-red-400' : sub.risk === 'medium' ? 'bg-yellow-400' : 'bg-green-400'} />
              </Card>
            ))}
          </div>
        </section>

        <section>
          <h2 className="text-lg font-bold text-slate-800 mb-3">How to Help at Home</h2>
          <div className="space-y-3">
            {PARENT_TIPS.map((tip, i) => (
              <div key={i} className="flex gap-3 bg-white p-4 rounded-2xl border border-slate-100 items-start">
                <span className="text-blue-500 text-lg">💡</span>
                <p className="text-sm text-slate-600 leading-relaxed">{tip}</p>
              </div>
            ))}
          </div>
        </section>

        <section>
          <h2 className="text-lg font-bold text-slate-800 mb-3">Teacher Notes</h2>
          <Card className="border-l-4 border-l-blue-500">
             <div className="flex justify-between items-start mb-2">
               <span className="font-bold text-slate-800 text-sm">Ms. Henderson</span>
               <span className="text-[10px] text-slate-400">Oct 14</span>
             </div>
             <p className="text-xs text-slate-600 mb-4">"Alex is a delight in class. We're working on making sure those math homework assignments get in on time!"</p>
             <button className="w-full py-3 bg-blue-50 text-blue-600 rounded-xl font-bold text-xs active:scale-95 transition-transform">
               Reply to Ms. Henderson
             </button>
          </Card>
        </section>

        <button className="w-full bg-slate-800 text-white py-4 rounded-3xl font-bold shadow-lg mt-4 active:scale-95 transition-transform flex items-center justify-center gap-2">
           <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
           Message School Counselor
        </button>
