import React, { useState, useEffect } from 'react';
import { Role, Student } from './types';
import { MOCK_STUDENTS } from './constants';
import { BottomNav } from './components/Shared';
import { StudentDashboard, ProgressDetail, HelpRequest } from './screens/StudentScreens';
import { TeacherDashboard, TeacherStudentDetail } from './screens/TeacherScreens';
import { ParentDashboard } from './screens/ParentScreens';

const App: React.FC = () => {
  const [role, setRole] = useState<Role | null>(null);
  const [currentScreen, setCurrentScreen] = useState<string>('dashboard');
  const [activeTab, setActiveTab] = useState<string>('home');
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(MOCK_STUDENTS[0]);

  // Bottom Navigation Icons (Lucide-like SVG)
  const navIcons = {
    home: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>,
    progress: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>,
    help: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
    messages: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>,
    alerts: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>,
    students: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>,
    resources: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
  };

  const navigateTo = (screen: string, data?: any) => {
    setCurrentScreen(screen);
    if (data) setSelectedStudent(data);
    window.scrollTo(0,0);
  };

  const handleTabChange = (tabId: string) => {
    setActiveTab(tabId);
    if (tabId === 'home') setCurrentScreen('dashboard');
    if (tabId === 'help') setCurrentScreen('help_request');
    if (tabId === 'progress') setCurrentScreen('progress_detail');
    if (tabId === 'students') setCurrentScreen('dashboard');
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-8">
        <div className="w-20 h-20 bg-blue-100 rounded-3xl flex items-center justify-center mb-6 text-3xl font-bold text-blue-600">SB</div>
        <h1 className="text-3xl font-bold text-slate-800 mb-2">SchoolBridge</h1>
        <p className="text-slate-500 text-center mb-10">Select your role to explore the prototype</p>

        <div className="w-full space-y-4 max-w-sm">
          {[
            { id: 'student', label: 'I am a Student', icon: '🎓' },
            { id: 'teacher', label: 'I am a Teacher', icon: '📝' },
            { id: 'parent', label: 'I am a Parent', icon: '🏠' },
          ].map(r => (
            <button 
              key={r.id}
              onClick={() => setRole(r.id as Role)}
              className="w-full bg-slate-50 border border-slate-100 p-6 rounded-3xl text-left hover:bg-slate-100 transition-colors flex items-center gap-4"
            >
              <span className="text-3xl">{r.icon}</span>
              <span className="font-bold text-slate-700">{r.label}</span>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto min-h-screen bg-slate-50 px-5 pt-4 pb-24 relative shadow-2xl">
      <div className="flex justify-between items-center mb-2 px-1">
        <span className="text-[10px] font-bold text-blue-600 tracking-widest uppercase">SchoolBridge Prototype</span>
        <button onClick={() => { setRole(null); setCurrentScreen('dashboard'); }} className="text-[10px] text-slate-400 font-bold uppercase underline">Switch Role</button>
      </div>

      <main>
        {role === 'student' && (
          <>
            {currentScreen === 'dashboard' && <StudentDashboard student={MOCK_STUDENTS[0]} onNavigate={navigateTo} />}
            {currentScreen === 'progress_detail' && <ProgressDetail student={MOCK_STUDENTS[0]} onNavigate={navigateTo} />}
            {currentScreen === 'help_request' && <HelpRequest student={MOCK_STUDENTS[0]} onNavigate={navigateTo} />}
          </>
        )}

        {role === 'teacher' && (
          <>
            {currentScreen === 'dashboard' && <TeacherDashboard onNavigate={navigateTo} />}
            {currentScreen === 'student_detail' && selectedStudent && <TeacherStudentDetail student={selectedStudent} onNavigate={navigateTo} />}
          </>
        )}

        {role === 'parent' && (
          <>
            {currentScreen === 'dashboard' && <ParentDashboard student={MOCK_STUDENTS[0]} onNavigate={navigateTo} />}
          </>
        )}
      </main>

      {/* Role-specific Bottom Navigation */}
      {role === 'student' && (
        <BottomNav 
          activeTab={activeTab} 
          onChange={handleTabChange} 
          items={[
            { id: 'home', label: 'Home', icon: navIcons.home },
            { id: 'progress', label: 'Progress', icon: navIcons.progress },
            { id: 'help', label: 'Help', icon: navIcons.help },
            { id: 'messages', label: 'Chat', icon: navIcons.messages },
          ]}
        />
      )}
      {role === 'teacher' && (
        <BottomNav 
          activeTab={activeTab} 
          onChange={handleTabChange} 
          items={[
            { id: 'home', label: 'Class', icon: navIcons.home },
            { id: 'students', label: 'Students', icon: navIcons.students },
            { id: 'alerts', label: 'Alerts', icon: navIcons.alerts },
            { id: 'resources', label: 'Library', icon: navIcons.resources },
          ]}
        />
      )}
      {role === 'parent' && (
        <BottomNav 
          activeTab={activeTab} 
          onChange={handleTabChange} 
          items={[
            { id: 'home', label: 'Home', icon: navIcons.home },
            { id: 'progress', label: 'Grades', icon: navIcons.progress },
            { id: 'messages', label: 'Teacher', icon: navIcons.messages },
          ]}
        />
      )}
    </div>
  );
};

export default App;
